<#
.SYNOPSIS
    Start the project-skyscraper.com change monitor daemon.
.DESCRIPTION
    Launches monitor_site.py as a continuous polling daemon that detects
    site changes and automatically fetches updated content into the mirror.
    Runs until Ctrl+C is pressed.
.EXAMPLE
    .\start_monitor.ps1
    .\start_monitor.ps1 -Quiet
#>

param(
    [switch]$Quiet
)

$ErrorActionPreference = "Stop"
$ScriptDir = Split-Path -Parent $PSCommandPath

# Check Python availability
$pythonCmd = $null
foreach ($cmd in @("python", "python3")) {
    $ver = & $cmd --version 2>$null
    if ($LASTEXITCODE -eq 0) {
        $pythonCmd = $cmd
        break
    }
}

if (-not $pythonCmd) {
    Write-Error "Python 3 is required but not found in PATH."
    exit 1
}

$monitorPy = Join-Path $ScriptDir "monitor_site.py"

